package com.veetu.vadagai.invoice;import com.veetu.vadagai.common.ApiResponse;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.nio.charset.StandardCharsets;import java.util.UUID;
@RestController @RequestMapping("/api/v1/invoices") public class InvoiceController{@GetMapping("/{paymentId}/pdf") ResponseEntity<byte[]> pdf(@PathVariable UUID paymentId){byte[] body=("Veetu Vadagai Receipt\nPayment: "+paymentId+"\nThank you").getBytes(StandardCharsets.UTF_8);return ResponseEntity.ok().header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=receipt-"+paymentId+".txt").contentType(MediaType.TEXT_PLAIN).body(body);}@GetMapping ApiResponse<String> list(){return ApiResponse.ok("Invoices module ready","Export PDF/Excel endpoints are cloud-storage ready");}}
